using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n, ans;
struct note
{
	int t, s;
} a[100001];
bool cmp(note x, note y)
{
	return x.s < y.s;
}
bool xx(int x)
{
	FOR(i,1,n) 
	{
		if (a[i].t + x < a[i].s)x += a[i].t;
		else return false;
	}
	return true;
}
signed main(void)
{
	cin >> n;
	FOR(i,1,n)cin >> a[i].t >> a[i].s;
	sort(a + 1, a + n + 1, cmp);
	int l = 0, r = 10000000;
	while (l <= r)
	{
		int mid = (l + r) / 2;
		if (xx(mid))l = mid + 1, ans = mid + 1;
		else r = mid - 1;
	}
	if (ans == 0)cout << -1;
	else cout << ans;
	return false;
}
